    def navigate_to(self, url):
        """Navigate to a URL"""
        if not url.startswith(('http://', 'https://')):
            url = 'https://' + url
        print(f"Navigating to: {url}")
        self.web_view.setUrl(QUrl(url))

    def navigate_from_bar(self):
        """Handle navigation from URL bar"""
        text = self.url_bar.text().strip()
        if not text:
            return

        # Check if it looks like a URL
        if ('.' in text and ' ' not in text) or text.startswith(('http://', 'https://', 'www.')):
            self.navigate_to(text)
        else:
            # Treat as Google search
            self.search_google()

    def search_google(self):
        """Search Google with the text in the URL bar"""
        query = self.url_bar.text().strip()
        if not query:
            self.navigate_to("https://www.google.com")
            return

        import urllib.parse
        search_url = f"https://www.google.com/search?q={urllib.parse.quote(query)}"
        print(f"Searching Google for: {query}")
        self.navigate_to(search_url)

    def search_youtube(self):
        """Search YouTube with the text in the URL bar"""
        query = self.url_bar.text().strip()
        if not query:
            self.navigate_to("https://www.youtube.com")
            return

        import urllib.parse
        search_url = f"https://www.youtube.com/results?search_query={urllib.parse.quote(query)}"
        print(f"Searching YouTube for: {query}")
        self.navigate_to(search_url)

    def go_back(self):
        """Go back in history"""
        self.web_view.back()
        print("Going back")

    def go_forward(self):
        """Go forward in history"""
        self.web_view.forward()
        print("Going forward")

    def reload_page(self):
        """Reload current page"""
        self.web_view.reload()
        print("Reloading page")

    def go_home(self):
        """Go to Google homepage"""
        self.navigate_to("https://www.google.com")
        print("Going home (Google)")

    def update_url_bar(self, url):
        """Update URL bar when page changes"""
        self.url_bar.setText(url.toString())
        self.url_bar.setCursorPosition(0)

    def update_title(self, title):
        """Update window title"""
        if title:
            self.setWindowTitle(f"{title} - Python Browser")
        else:
            self.setWindowTitle("Python Browser - Google & YouTube")

    def on_load_started(self):
        """Handle page load start"""
        self.progress_bar.setVisible(True)
        self.progress_bar.setValue(0)
        self.status_bar.showMessage("Loading...")
        self.reload_btn.setText("X")
        self.reload_btn.setToolTip("Stop Loading")
        self.reload_btn.clicked.disconnect()
        self.reload_btn.clicked.connect(self.web_view.stop)

    def on_load_progress(self, progress):
        """Handle page load progress"""
        self.progress_bar.setValue(progress)

    def on_load_finished(self, success):
        """Handle page load completion"""
        self.progress_bar.setVisible(False)
        if success:
            self.status_bar.showMessage("Page loaded successfully", 3000)
            print(f"Page loaded: {self.web_view.url().toString()}")
        else:
            self.status_bar.showMessage("Failed to load page", 3000)
            print("Page load failed")

        self.reload_btn.setText("R")
        self.reload_btn.setToolTip("Reload Page")
        try:
            self.reload_btn.clicked.disconnect()
        except TypeError:
            pass
        self.reload_btn.clicked.connect(self.reload_page)

        # Update back/forward button states
        self.back_btn.setEnabled(self.web_view.history().canGoBack())
        self.forward_btn.setEnabled(self.web_view.history().canGoForward())


